import{c as e,Q as a,j as o,m as i}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),r={name:"guide/index.md"};function n(s,t,d,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><h2 id="start-dictating" tabindex="-1">Start Dictating <a class="header-anchor" href="#start-dictating" aria-label="Permalink to &quot;Start Dictating&quot;">​</a></h2><ol><li>Open a file or click into a terminal in VS Code</li><li>Press <strong><code>Cmd+Shift+D</code></strong> (macOS) or <strong><code>Ctrl+Shift+D</code></strong> (Windows)</li><li>Speak — you&#39;ll see partial text in the status bar</li><li>Press the same key combo again to stop — text is inserted at your cursor</li></ol><p>That&#39;s it. Your words appear wherever your cursor was when you started recording.</p><h2 id="keybindings" tabindex="-1">Keybindings <a class="header-anchor" href="#keybindings" aria-label="Permalink to &quot;Keybindings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Cmd+Shift+D</code> / <code>Ctrl+Shift+D</code></td><td>Toggle dictation on/off</td></tr><tr><td><code>Cmd+Shift+Space</code> / <code>Ctrl+Shift+Space</code></td><td>Stop dictation</td></tr><tr><td><code>Escape</code></td><td><strong>Cancel</strong> dictation (discards text)</td></tr></tbody></table><h2 id="status-bar" tabindex="-1">Status Bar <a class="header-anchor" href="#status-bar" aria-label="Permalink to &quot;Status Bar&quot;">​</a></h2><p>The status bar (bottom right) shows:</p><ul><li><strong>Idle:</strong> <code>🎤 Default</code> — microphone name, click to change</li><li><strong>Recording:</strong> <code>🎤 Recording...</code> with red background, shows partial text as you speak</li><li><strong>Processing:</strong> Cycling rainbow colors with a spinner — gateway is enhancing your text (see <a href="/guide/gateway.html">Gateway Setup</a>)</li><li><strong>Mode Selector:</strong> Shows current mode (Auto/Markdown/Code/Terminal/Commit/Magic) — click to cycle (see <a href="/guide/modes.html">Processing Modes</a>)</li><li><strong>Error:</strong> <code>⚠️ Mic Error</code> — check permissions</li></ul><h2 id="audio-feedback" tabindex="-1">Audio Feedback <a class="header-anchor" href="#audio-feedback" aria-label="Permalink to &quot;Audio Feedback&quot;">​</a></h2><p>You&#39;ll hear short tones:</p><ul><li><strong>Start:</strong> a light &quot;tink&quot; when recording begins</li><li><strong>Stop:</strong> a &quot;pop&quot; when recording ends and text is inserted</li><li><strong>Cancel:</strong> a low &quot;basso&quot; when you press ESC to discard</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/guide/configuration.html">Configure settings</a> — language, engine, insert mode</li><li><a href="/guide/gateway.html">AI Gateway</a> — enhance dictation with language models</li><li><a href="/guide/modes.html">Processing Modes</a> — choose how your text is formatted</li><li><a href="/guide/terminal.html">Use with terminals</a> — dictate into Claude Code</li><li><a href="/guide/microphone.html">Select a microphone</a> — choose your input device</li></ul>',14)])])}const m=e(r,[["render",n]]);export{g as __pageData,m as default};
